kubectl patch statefulset elasticsearch -n elasticsearch --type=strategic-merge-patch -p '{
  "spec": {
    "template": {
      "spec": {
        "containers": [
          {
            "name": "elasticsearch",
            "env": [
              {
                "name": "ES_LOG_STYLE",
                "value": "file"
              }
            ],
            "volumeMounts": [
              {
                "name": "es-logs",
                "mountPath": "/usr/share/elasticsearch/logs"
              }
            ]
          },
          {
            "name": "metricbeat",
            "image": "docker.elastic.co/beats/metricbeat:7.17.9",
            "args": ["-c", "/etc/metricbeat/metricbeat.yml", "-e", "--strict.perms=false"],
            "env": [
              {
                "name": "ELASTIC_PASSWORD",
                "valueFrom": {
                  "secretKeyRef": {
                    "name": "elastic-password",
                    "key": "password"
                  }
                }
              }
            ],
            "volumeMounts": [
              {
                "name": "metricbeat-config",
                "mountPath": "/etc/metricbeat/metricbeat.yml",
                "subPath": "metricbeat.yml"
              },
              {
                "name": "es-http-ca",
                "mountPath": "/usr/share/metricbeat/certs/ca.crt",
                "subPath": "ca.crt"
              }
            ]
          },
          {
            "name": "filebeat",
            "image": "docker.elastic.co/beats/filebeat:7.17.9",
            "args": ["-c", "/etc/filebeat/filebeat.yml", "-e", "--strict.perms=false"],
            "volumeMounts": [
              {
                "name": "filebeat-config",
                "mountPath": "/etc/filebeat/filebeat.yml",
                "subPath": "filebeat.yml"
              },
              {
                "name": "es-logs",
                "mountPath": "/var/log/elasticsearch",
                "readOnly": true
              }
            ]
          }
        ],
        "volumes": [
          {
            "name": "es-logs",
            "emptyDir": {}
          },
          {
            "name": "metricbeat-config",
            "configMap": {
              "name": "metricbeat-config"
            }
          },
          {
            "name": "filebeat-config",
            "configMap": {
              "name": "filebeat-config"
            }
          },
          {
            "name": "es-http-ca",
            "configMap": {
              "name": "es-http-ca"
            }
          }
        ]
      }
    }
  }
}'

